          "group": "Nutrition",
          "critical": false,
          "correct": false,
          "phase": 1,
          "teaching": "NPO/bowel rest is OUTDATED for pancreatitis. Early enteral nutrition (within 24-48h) via NG or NJ tube is superior to NPO \u2014 maintains gut mucosal integrity, reduces infectious complications, and improves mortality. Start oral feeding as soon as tolerated. TPN only if enteral nutrition fails.",
          "references": [
            {
              "source": "Acute Pancreatitis \u2014 StatPearls",
              "url": "https://www.ncbi.nlm.nih.gov/books/NBK482468/",
              "detail": "Early enteral nutrition preferred over NPO; reduces infectious complications and mortality"
            }
          ]
